import{_ as a,o as t,c as e,a2 as i}from"./chunks/framework.BWuWLRhz.js";const d="/assets/02-first-session-flow@2x.DWTmz9D6.png",g=JSON.parse('{"title":"02 · 安装与使用","description":"","frontmatter":{"head":[["meta",{"property":"og:site_name","content":"David Studio AI 编程指南"}]]},"headers":[],"relativePath":"claude-code/02-install.md","filePath":"claude-code/02-install.md"}'),n={name:"claude-code/02-install.md"};function o(l,s,p,h,c,r){return t(),e("div",null,[...s[0]||(s[0]=[i(`<h1 id="_02-·-安装与使用" tabindex="-1">02 · 安装与使用 <a class="header-anchor" href="#_02-·-安装与使用" aria-label="Permalink to &quot;02 · 安装与使用&quot;">​</a></h1><blockquote><p>📚 <strong>系列导航</strong>：上一篇 <a href="./01-what-is-claude-code">01 · Claude Code 简介</a> 讲清了它是什么、能干啥。这一篇带你真正把它装到自己电脑上，登录、跑起来，顺带把升级、卸载、踩坑排查一次说透。下一篇 <a href="./03-how-it-works">03 · Claude Code 如何工作</a> 掀开盖子看代理循环。</p></blockquote><p>说个常见的糗事。很多人第一次装 Claude Code，随手搜了篇老教程，照着敲 <code>npm install -g @anthropic-ai/claude-code</code>，卡在权限报错上。一着急直接 <code>sudo</code> 怼上去——装是装上了，后面自动更新天天失败，<code>claude doctor</code> 一片红。折腾快一个钟头才反应过来：<strong>官方早已把原生脚本列为首选，npm 那条路坑更多</strong>，一行 <code>curl</code> 脚本三十秒搞定的事，却硬走了最绕、最容易踩坑的那条道。</p><p>说白了，<strong>装 Claude Code 本身不难，难的是没人告诉你哪条路是坑</strong>。这篇就把每个平台的正路标清楚，让你别重蹈覆辙。</p><p><strong>看完这一篇，你会拿到：</strong></p><ul><li>一条命令在 Mac / Windows / Linux / WSL 上把 Claude Code 装好（带预期输出，能自己验证装没装成功）</li><li>三种安装方式（官方脚本 / 包管理器 / npm）的对比，知道自己该选哪个</li><li>登录、升级、卸载的完整操作</li><li>一份「报错 → 怎么修」的速查表，覆盖九成新手会撞上的坑</li></ul><hr><h2 id="_01-装之前先搞清楚三件事" tabindex="-1">01 装之前先搞清楚三件事 <a class="header-anchor" href="#_01-装之前先搞清楚三件事" aria-label="Permalink to &quot;01 装之前先搞清楚三件事&quot;">​</a></h2><p>别急着敲命令。太多人装到一半才发现「哦这账号还不能用」，白折腾。三件事先确认一下。</p><h3 id="第一件-你的电脑够不够格" tabindex="-1">第一件：你的电脑够不够格 <a class="header-anchor" href="#第一件-你的电脑够不够格" aria-label="Permalink to &quot;第一件：你的电脑够不够格&quot;">​</a></h3><p>Claude Code 对机器要求不高，但有几条硬线（<strong>以官方为准</strong>）：</p><table tabindex="0"><thead><tr><th>项目</th><th>要求</th></tr></thead><tbody><tr><td><strong>操作系统</strong></td><td>macOS 13.0+ / Windows 10 1809+ / Ubuntu 20.04+ / Debian 10+ / Alpine 3.19+</td></tr><tr><td><strong>内存</strong></td><td>4 GB 以上可用 RAM</td></tr><tr><td><strong>处理器</strong></td><td>x64 或 ARM64</td></tr><tr><td><strong>网络</strong></td><td>需要联网</td></tr><tr><td><strong>终端</strong></td><td>Bash、Zsh、PowerShell 或 CMD 任一</td></tr></tbody></table><p>macOS 低于 13.0 的注意：<strong>装是能装，但一跑就崩</strong>，报 <code>dyld: cannot load</code> 之类的错——老系统不支持二进制用的指令，没有绕过办法，只能升级系统（在还停留在 macOS 12 的机器上，它死活跑不起来，升到 14 才好）。</p><h3 id="第二件-你得有个能用的账号" tabindex="-1">第二件：你得有个能用的账号 <a class="header-anchor" href="#第二件-你得有个能用的账号" aria-label="Permalink to &quot;第二件：你得有个能用的账号&quot;">​</a></h3><p><strong>新手最容易忽略的一条：免费版 Claude.ai 账号用不了 Claude Code。</strong></p><p>官方要求是 <strong>Pro、Max、Team、Enterprise 或 Console（API）账号</strong>之一。你平时用网页版 Claude 聊得挺欢，不代表账号能驱动 Claude Code——免费档就是不行。</p><p>想用国产模型（DeepSeek、GLM、Minimax）省钱的，账号这步先放着，第 05 篇专门讲接第三方模型。本篇默认你用官方账号。</p><h3 id="第三件-你打算从哪儿用它" tabindex="-1">第三件：你打算从哪儿用它 <a class="header-anchor" href="#第三件-你打算从哪儿用它" aria-label="Permalink to &quot;第三件：你打算从哪儿用它&quot;">​</a></h3><p>Claude Code 有三种用法：<strong>CLI（命令行）</strong> 功能最全、最贴近设计初衷；<strong>桌面 App</strong> 不用碰终端、下载即用；<strong>编辑器集成</strong>（VS Code / JetBrains）融进现有开发流。</p><p><strong>我的建议：直接学 CLI。</strong> 这篇也以 CLI 为主线——它最稳、最通用，学会它后面桌面 App 和编辑器插件都是几分钟的事（第 08-10 篇会讲）。实在抵触终端的，去 <a href="https://claude.com/download" target="_blank" rel="noreferrer">https://claude.com/download</a> 下桌面 App，点点就能用。</p><blockquote><p>💡 一句话总结：开装前确认三件事——<strong>系统版本够、账号是付费档或 Console、用法选 CLI</strong>，这三关过了再敲命令。</p></blockquote><hr><h2 id="_02-装好它-每个平台一条命令" tabindex="-1">02 装好它：每个平台一条命令 <a class="header-anchor" href="#_02-装好它-每个平台一条命令" aria-label="Permalink to &quot;02 装好它：每个平台一条命令&quot;">​</a></h2><p>先给结论：<strong>所有平台都优先用官方安装脚本</strong>（官方叫「原生安装 / Native Install」，现在最推荐）。最大好处是——<strong>装完后台自动更新，基本不用再操心版本</strong>。</p><p><strong>类比：原生安装就像应用商店装 App。</strong> 点一下「安装」，它自己下载、自己装好、以后自己后台更新；老的 npm 方式更像「下个安装包手动点下一步」——能装，但更新得你亲自来，还容易因权限出岔子。</p><h3 id="macos-linux-wsl" tabindex="-1">macOS / Linux / WSL <a class="header-anchor" href="#macos-linux-wsl" aria-label="Permalink to &quot;macOS / Linux / WSL&quot;">​</a></h3><p>打开终端，粘这一行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://claude.ai/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><p>国内网络提示：<code>claude.ai</code> 和下载服务器 <code>downloads.claude.ai</code> 多数情况下需要<strong>魔法上网</strong>才能稳定访问。装的时候挂上代理，能省掉一大半「卡住 / 超时」的报错。</p><h3 id="windows-原生-不用-wsl" tabindex="-1">Windows（原生，不用 WSL） <a class="header-anchor" href="#windows-原生-不用-wsl" aria-label="Permalink to &quot;Windows（原生，不用 WSL）&quot;">​</a></h3><p><strong>先确认你在哪个终端里</strong>——这是 Windows 用户最常翻车的点，PowerShell 和 CMD 命令不一样：</p><p>PowerShell（提示符长这样 <code>PS C:\\&gt;</code>）：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">irm https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">claude.ai</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">install.ps1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> iex</span></span></code></pre></div><p>CMD（提示符是 <code>C:\\&gt;</code>，没有前面的 <code>PS</code>）：</p><div class="language-batch vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">batch</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl -fsSL https://claude.ai/install.cmd -o install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> del</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> install.cmd</span></span></code></pre></div><p><strong>怎么分辨？</strong> 看提示符开头有没有 <code>PS</code>：有就是 PowerShell，没有就是 CMD。在 PowerShell 里跑 CMD 那条带 <code>&amp;&amp;</code> 的命令会报 <code>The token &#39;&amp;&amp;&#39; is not a valid statement separator</code>，反过来在 CMD 里跑 <code>irm</code> 会报 <code>&#39;irm&#39; is not recognized</code>——看到这俩报错换对应命令即可。</p><p><strong>开着魔法上网，在 CMD 里装还是卡住 / 超时？</strong> 这是个真坑：多数代理客户端默认的「系统代理」模式，CMD 里的 <code>curl</code> 根本不认——它不读 Windows 的系统代理设置，照样直连，所以代理开了等于没开。装之前先在<strong>同一个 CMD 窗口</strong>里手动设代理（<code>7890</code> 换成你代理客户端实际的 HTTP 端口，在客户端设置里能看到）：</p><div class="language-batch vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">batch</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">set</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> http_proxy</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http://127.0.0.1:7890</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">set</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> https_proxy</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http://127.0.0.1:7890</span></span></code></pre></div><p>设完再跑上面那条安装命令。嫌麻烦还有两条路：换 PowerShell 跑 <code>irm</code> 那条（它默认走系统代理，没这毛病），或在代理客户端里打开 TUN 模式（有的叫「增强模式」「虚拟网卡」），让全部流量强制过代理。</p><p>另外，Windows 原生环境<strong>推荐顺手装个 <a href="https://git-scm.com/downloads/win" target="_blank" rel="noreferrer">Git for Windows</a></strong>，它给 Claude Code 提供 Git Bash；不装会改用 PowerShell 跑命令（也能用，只是部分 Bash 脚本受限）。WSL 则不需要它。</p><h3 id="windows-选-wsl-还是原生" tabindex="-1">Windows 选 WSL 还是原生？ <a class="header-anchor" href="#windows-选-wsl-还是原生" aria-label="Permalink to &quot;Windows 选 WSL 还是原生？&quot;">​</a></h3><p>做 Linux 工具链开发、或想用<a href="https://code.claude.com/docs/zh-CN/sandboxing" target="_blank" rel="noreferrer">沙箱</a>功能就走 WSL。官方对照表：</p><table tabindex="0"><thead><tr><th>选项</th><th>需要什么</th><th style="text-align:center;">支持沙箱</th><th>什么时候用</th></tr></thead><tbody><tr><td><strong>原生 Windows</strong></td><td>啥都不用（Git for Windows 可选）</td><td style="text-align:center;">❌</td><td>Windows 原生项目和工具</td></tr><tr><td><strong>WSL 2</strong></td><td>启用 WSL 2</td><td style="text-align:center;">✅</td><td>Linux 工具链或要用沙箱</td></tr><tr><td><strong>WSL 1</strong></td><td>启用 WSL 1</td><td style="text-align:center;">❌</td><td>WSL 2 用不了时的退路</td></tr></tbody></table><p>走 WSL 的话，<strong>在 WSL 终端里</strong>跑上面 macOS/Linux 那条 <code>curl</code> 脚本就行——是在 WSL 里装，不是在 PowerShell 里。</p><h3 id="不想碰终端-还有别的路" tabindex="-1">不想碰终端？还有别的路 <a class="header-anchor" href="#不想碰终端-还有别的路" aria-label="Permalink to &quot;不想碰终端？还有别的路&quot;">​</a></h3><p>官方脚本之外还有几条备选道，列个对比按需挑：</p><table tabindex="0"><thead><tr><th>安装方式</th><th>命令</th><th style="text-align:center;">自动更新</th><th>我的建议</th></tr></thead><tbody><tr><td><strong>官方脚本</strong></td><td><code>curl ... | bash</code></td><td style="text-align:center;">✅ 后台自动</td><td><strong>首选</strong>，省心</td></tr><tr><td><strong>Homebrew</strong>（macOS）</td><td><code>brew install --cask claude-code</code></td><td style="text-align:center;">❌ 手动</td><td>已经重度用 brew 管软件的人</td></tr><tr><td><strong>WinGet</strong>（Windows）</td><td><code>winget install Anthropic.ClaudeCode</code></td><td style="text-align:center;">❌ 手动</td><td>习惯用 WinGet 的人</td></tr><tr><td><strong>npm</strong></td><td><code>npm install -g @anthropic-ai/claude-code</code></td><td style="text-align:center;">❌ 手动</td><td><strong>最后才考虑</strong>，要先装 Node.js 18+</td></tr></tbody></table><p>几个坑提前说：</p><ul><li><strong>Homebrew 有两个 cask</strong>：<code>claude-code</code> 是稳定版（慢一周、跳过有重大回归的版本），<code>claude-code@latest</code> 是最新版，升级各对应 <code>brew upgrade claude-code</code> / <code>brew upgrade claude-code@latest</code>。</li><li><strong>WinGet 不自动更新</strong>：需定期手动跑 <code>winget upgrade Anthropic.ClaudeCode</code>。</li><li><strong>npm 千万别加 <code>sudo</code></strong>。官方明确警告 <code>sudo npm install -g</code> 会引发权限问题和安全风险——这正是开头那个最常见的坑。遇到权限报错，正解是改用官方脚本。npm 升级也要用 <code>npm install -g ...@latest</code>，别用 <code>npm update -g</code>。</li></ul><blockquote><p>💡 一句话总结：闭眼选官方脚本就对了，<strong>一条 <code>curl</code>（或 Windows 的 <code>irm</code>）解决战斗，还自带后台更新</strong>；npm 是下下策，且永远别 <code>sudo</code>。</p></blockquote><hr><h2 id="_03-验证装没装成功" tabindex="-1">03 验证装没装成功 <a class="header-anchor" href="#_03-验证装没装成功" aria-label="Permalink to &quot;03 验证装没装成功&quot;">​</a></h2><p>装完别急着用，花十秒确认一下。打开一个新终端窗口，敲：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><p>预期输出是一个版本号，类似（你看到的数字会更新，正常）：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2.1.81 (Claude Code)</span></span></code></pre></div><p><strong>看到版本号 = 装成功了。</strong> 如果报 <code>command not found: claude</code> 或 Windows 上的 <code>&#39;claude&#39; is not recognized</code>，先别重装——九成是 PATH 没配好（安装目录没进系统搜索路径），第 06 节有修法。</p><p>想更详细，官方还给了个体检命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre></div><p>它会把安装情况、配置、最近一次更新结果都列出来。<strong>装完新机器或遇到抽风，第一反应就该是先跑一遍 <code>claude doctor</code></strong>——比自己瞎猜快多了。</p><blockquote><p>💡 一句话总结：<code>claude --version</code> 出版本号就成了；有任何不对劲，<code>claude doctor</code> 是你的第一诊断工具。</p></blockquote><hr><h2 id="_04-登录-让它认得你" tabindex="-1">04 登录：让它认得你 <a class="header-anchor" href="#_04-登录-让它认得你" aria-label="Permalink to &quot;04 登录：让它认得你&quot;">​</a></h2><p>装好的 Claude Code 还是个「不认识你」的空壳，得登录绑上账号才能干活。在你的<strong>项目目录</strong>里启动它：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span></span></code></pre></div><p>首次启动它会自动引导你登录，也可以进界面后手动触发：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/login</span></span></code></pre></div><p>接下来它弹出浏览器页面让你授权，授权完回终端就登录上了。<strong>凭据存在本地，下次启动不用再登</strong>。换账号再跑一次 <code>/login</code> 即可。</p><h3 id="登录卡住了怎么办" tabindex="-1">登录卡住了怎么办 <a class="header-anchor" href="#登录卡住了怎么办" aria-label="Permalink to &quot;登录卡住了怎么办&quot;">​</a></h3><p>最常见的一种：<strong>浏览器没自动弹出，或你在远程服务器 / WSL / SSH 里登录</strong>——浏览器可能开在另一台机器上，回调回不来。官方办法很简单：</p><p>在登录提示界面按 <code>c</code>，把那串 OAuth（开放授权）URL 复制出来，手动粘到浏览器打开，登录完显示一个 code，再把 code 贴回终端即可。</p><p>在云服务器上配 Claude Code 时很容易吃这亏，傻等浏览器弹窗半天没反应——远程环境就得走「复制 URL 手动开」这条路。连粘贴都不灵的话，还有个更稳的退路命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span></span></code></pre></div><p>它从标准输入读取你粘贴的 code，专治交互式提示粘不进去的终端。</p><h3 id="一个隐蔽的登录大坑" tabindex="-1">一个隐蔽的登录大坑 <a class="header-anchor" href="#一个隐蔽的登录大坑" aria-label="Permalink to &quot;一个隐蔽的登录大坑&quot;">​</a></h3><p>登录后报 <code>This organization has been disabled</code>，但订阅明明是好的——<strong>大概率是 shell 配置里残留了一个旧的 <code>ANTHROPIC_API_KEY</code></strong>，把你的订阅凭据顶掉了。</p><p>环境变量里有 API key 时，Claude Code 会优先用 key 而非订阅。解法是清掉它：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">unset</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ANTHROPIC_API_KEY</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span></span></code></pre></div><p>要永久解决，去翻 <code>~/.zshrc</code>、<code>~/.bashrc</code> 或 <code>~/.profile</code>，把那行 <code>export ANTHROPIC_API_KEY=...</code> 删掉。进 Claude Code 后用 <code>/status</code> 能确认当前在用哪种登录方式。</p><blockquote><p>💡 一句话总结：<code>claude</code> 启动会自动引导登录，<strong>远程/WSL 环境记住「按 <code>c</code> 复制 URL 手动开」</strong>；登录报组织禁用，先查环境变量里有没有残留的旧 API key。</p></blockquote><hr><h2 id="_05-升级与卸载" tabindex="-1">05 升级与卸载 <a class="header-anchor" href="#_05-升级与卸载" aria-label="Permalink to &quot;05 升级与卸载&quot;">​</a></h2><h3 id="升级" tabindex="-1">升级 <a class="header-anchor" href="#升级" aria-label="Permalink to &quot;升级&quot;">​</a></h3><p><strong>用官方脚本装的啥都不用做</strong>——后台自动更新，下次启动就是新版。想立刻更：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span></code></pre></div><p>更新成没成，还是那句 <code>claude doctor</code>。更新渠道可选（写在 <code>settings.json</code>，或在 Claude Code 内用 <code>/config</code> 设）：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;autoUpdatesChannel&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;stable&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><ul><li><code>&quot;latest&quot;</code>（默认）：新功能一发布就拿到</li><li><code>&quot;stable&quot;</code>：用大概一周前的版本，跳过有重大回归的发布——<strong>追求稳定选这个</strong></li></ul><p>不想要自动更新，在 <code>settings.json</code> 的 <code>env</code> 里设 <code>&quot;DISABLE_AUTOUPDATER&quot;: &quot;1&quot;</code> 即可（它只停后台检查，<code>claude update</code> 手动更新仍能用）。<strong>Homebrew / WinGet / apt 装的默认都不自动更新</strong>，得手动跑对应升级命令（前面坑提示里说了）。</p><h3 id="卸载" tabindex="-1">卸载 <a class="header-anchor" href="#卸载" aria-label="Permalink to &quot;卸载&quot;">​</a></h3><p>按你<strong>当初的安装方式</strong>对应卸载。官方脚本装的：</p><p>macOS / Linux / WSL：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.local/bin/claude</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.local/share/claude</span></span></code></pre></div><p>Windows PowerShell：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Remove-Item</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Path </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">USERPROFILE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">\\.local\\bin\\claude.exe&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Remove-Item</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Path </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">USERPROFILE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">\\.local\\share\\claude&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Recurse </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force</span></span></code></pre></div><p>其他方式各自对应：Homebrew 用 <code>brew uninstall --cask claude-code</code>，WinGet 用 <code>winget uninstall Anthropic.ClaudeCode</code>，npm 用 <code>npm uninstall -g @anthropic-ai/claude-code</code>。</p><p><strong>注意</strong>：上面这些只删了程序本体，配置、授权、会话历史还留在 <code>~/.claude/</code> 里。如果卸载后 <code>claude</code> 还能跑，多半是你有<strong>第二个安装</strong>或老版本留下的 shell 别名（第 06 节教你揪出来）。</p><p>想彻底清干净（<strong>这步不可恢复，设置 / 授权 / MCP 配置 / 会话历史全没</strong>）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 全局用户设置和状态</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.claude</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.claude.json</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 当前项目的本地设置（在项目目录里执行）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .claude</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .mcp.json</span></span></code></pre></div><p>提醒：VS Code 扩展、JetBrains 插件、桌面 App 也会往 <code>~/.claude/</code> 写东西，它们还装着这目录就会被重建——要彻底删得先卸了它们。</p><blockquote><p>💡 一句话总结：官方脚本装的<strong>升级靠后台自动、<code>claude update</code> 手动催</strong>；卸载按当初的装法对应来，<strong>配置文件得单独删、且删了不可逆</strong>。</p></blockquote><hr><h2 id="_06-报错速查-九成新手会撞的坑" tabindex="-1">06 报错速查：九成新手会撞的坑 <a class="header-anchor" href="#_06-报错速查-九成新手会撞的坑" aria-label="Permalink to &quot;06 报错速查：九成新手会撞的坑&quot;">​</a></h2><p>装这东西报错基本逃不掉，但绝大多数有标准解法。把官方文档里最高频的几类整理成速查表——<strong>先对症，再下药，别一报错就重装</strong>。</p><table tabindex="0"><thead><tr><th>你看到的报错</th><th>真正的原因</th><th>怎么修</th></tr></thead><tbody><tr><td><code>command not found: claude</code></td><td>安装目录没进 PATH</td><td>把 <code>~/.local/bin</code> 加进 PATH（见下方）</td></tr><tr><td><code>syntax error near unexpected token &#39;&lt;&#39;</code></td><td>安装脚本返回了 HTML 不是脚本</td><td>多半网络/区域问题，换 Homebrew/WinGet 或稍后重试</td></tr><tr><td><code>irm is not recognized</code></td><td>你在 CMD 里跑了 PowerShell 命令</td><td>换成 CMD 安装命令，或打开 PowerShell</td></tr><tr><td><code>&#39;&amp;&amp;&#39; is not valid</code></td><td>你在 PowerShell 里跑了 CMD 命令</td><td>换成 PowerShell 的 <code>irm</code> 命令</td></tr><tr><td><code>bash is not recognized</code></td><td>在 Windows 上跑了 Mac/Linux 命令</td><td>换成 PowerShell 的 <code>irm</code> 命令</td></tr><tr><td>开着魔法上网，CMD 里装仍卡住 / 超时</td><td>CMD 的 <code>curl</code> 不走系统代理，等于直连</td><td>CMD 里先 <code>set https_proxy=...</code> 再装（见第 02 节），或换 PowerShell / 开 TUN 模式</td></tr><tr><td>Linux 安装时 <code>Killed</code></td><td>内存不够（OOM 杀进程）</td><td>加交换空间（见下方），Claude Code 要 4GB+ RAM</td></tr><tr><td><code>Error loading shared library</code></td><td>安装器误判了系统 libc 类型，拉了错误变体</td><td>见官方 musl/glibc 排查</td></tr><tr><td>登录后 <code>403 Forbidden</code></td><td>订阅无效 / 账号没权限</td><td>查订阅状态，或确认 Console 账号有对应角色</td></tr><tr><td><code>App unavailable in region</code></td><td>你所在区域不支持</td><td>见 <a href="https://www.anthropic.com/supported-countries" target="_blank" rel="noreferrer">支持的国家/地区</a></td></tr></tbody></table><p>挑两个最高频的展开说。</p><h3 id="坑一-command-not-found-claude-最常见" tabindex="-1">坑一：<code>command not found: claude</code>（最常见） <a class="header-anchor" href="#坑一-command-not-found-claude-最常见" aria-label="Permalink to &quot;坑一：\`command not found: claude\`（最常见）&quot;">​</a></h3><p>跑 <code>claude</code> 说找不到命令——<strong>不是没装上，是装好的目录没进系统搜索路径（PATH）</strong>。</p><p><strong>类比：PATH 就是系统的门牌号清单。</strong> 程序装好好比房子盖好了，但系统只会去「门牌号清单」上登记过的地址挨个找。<code>claude</code> 的房子盖在 <code>~/.local/bin/</code>，这地址没登记进清单，自然找不到。</p><p>修法（macOS 默认是 Zsh）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;export PATH=&quot;$HOME/.local/bin:$PATH&quot;&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.zshrc</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.zshrc</span></span></code></pre></div><p>Linux 大多默认 Bash，把 <code>~/.zshrc</code> 换成 <code>~/.bashrc</code> 即可。改完验证：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><p>出版本号就修好了。Windows 用户则把 <code>%USERPROFILE%\\.local\\bin</code> 加进用户 PATH 环境变量，然后<strong>重启终端</strong>。</p><h3 id="坑二-揪出「打架」的多个安装" tabindex="-1">坑二：揪出「打架」的多个安装 <a class="header-anchor" href="#坑二-揪出「打架」的多个安装" aria-label="Permalink to &quot;坑二：揪出「打架」的多个安装&quot;">​</a></h3><p>如果先 npm 装过又官方脚本装一遍，可能同时存在好几个 <code>claude</code>，版本对不上、行为诡异。先看看 PATH 上有几个：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">which</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span></span></code></pre></div><p>列出来不止一个的话，<strong>只留官方脚本那个</strong>（<code>~/.local/bin/claude</code>），其余删掉：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 卸掉 npm 全局安装</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> uninstall</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @anthropic-ai/claude-code</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 删掉老版本的本地 npm 安装</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.claude/local</span></span></code></pre></div><p>很多时候 <code>which -a claude</code> 一跑，就会发现 npm 和原生各装了一个，删掉 npm 那个、理顺 PATH，瞬间清静。</p><blockquote><p>💡 一句话总结：<strong>报错先查表对因，别条件反射重装</strong>；找不到命令多半是 PATH，行为诡异多半是装了好几个在打架，<code>which -a claude</code> 一照便知。</p></blockquote><hr><h2 id="_07-动手-从零跑通第一次" tabindex="-1">07 动手：从零跑通第一次 <a class="header-anchor" href="#_07-动手-从零跑通第一次" aria-label="Permalink to &quot;07 动手：从零跑通第一次&quot;">​</a></h2><p>光装好不算数，实际跑一遍确认链路通。<strong>这个最小流程不依赖已有项目，新建个空目录就能做。</strong></p><p>第一步，建测试目录并进去，启动 Claude Code：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude-test</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude-test</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span></span></code></pre></div><p>第一次启动会引导你登录（按第 04 节走完），登录后看到欢迎界面。</p><p>第二步，在输入框里敲 <code>/help</code>，看看有哪些命令：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/help</span></span></code></pre></div><p>预期：弹出一份可用命令和功能说明的列表。直接打一个 <code>/</code>，还会弹出所有命令的自动补全。</p><p>第三步，让它干件实事——直接用大白话下指令（不用记命令格式）：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>在 test.py 文件里写一个打印 hello world 的函数</span></span></code></pre></div><p>预期行为：<strong>Claude Code 会先把要改的代码以 diff（差异对比）摆给你看，等你确认（选 yes）才真正写文件</strong>。这是它的核心工作流——先给方案、等你批、再动手，不偷偷改你东西。</p><p>确认后，目录里就多了个 <code>test.py</code>。退出：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>exit</span></span></code></pre></div><p>到这步，你已经完整跑通了「装 → 登录 → 给指令 → 它改文件 → 你确认」的全流程。<strong>第一次看到它自己写出代码、还停下来等你点头那一下，挺有「这玩意儿真能干活」的实感</strong>——头一回跑通的时候，多少会有点小兴奋。</p><p><img src="`+d+'" alt="Claude Code 首次会话全流程图"></p><p>这张图把上面四步串成一条线：从 <code>claude</code> 启动、登录、<code>/help</code> 看命令、大白话下指令，到最关键的一环——<strong>它先把 diff 摆给你看、等你点头（是）才写文件；你说不（否）它就不写，调整后再来一轮</strong>，全程绝不偷偷改你的东西。</p><blockquote><p>💡 一句话总结：新建空目录就能跑通全流程——<strong><code>claude</code> 启动登录、<code>/help</code> 看命令、大白话下指令、看 diff 点 yes</strong>，这套「先给方案再动手」是它最核心的节奏。</p></blockquote><hr><h2 id="_08-小结" tabindex="-1">08 小结 <a class="header-anchor" href="#_08-小结" aria-label="Permalink to &quot;08 小结&quot;">​</a></h2><p>这一篇把「装好并用起来」彻底过了一遍：</p><ul><li><strong>装前确认三件事</strong>：系统版本够、账号是付费档或 Console、用法选 CLI。</li><li><strong>认准官方脚本</strong>：Mac/Linux/WSL 用 <code>curl</code>，Windows 分清 PowerShell（<code>irm</code>）和 CMD；npm 是下策，永远别 <code>sudo</code>。</li><li><strong>验证用 <code>claude --version</code>，体检用 <code>claude doctor</code></strong>；登录报组织禁用先查残留的 <code>ANTHROPIC_API_KEY</code>。</li><li><strong>报错先查表对因</strong>：找不到命令查 PATH，行为诡异查多重安装。</li></ul><p>你现在应该能在自己机器上独立装好 Claude Code、登录、跑通第一个例子，遇到常见报错也知道往哪查。</p><p>下一篇 <strong><a href="./03-how-it-works">03 · Claude Code 如何工作</a></strong>——掀开盖子看里面：你刚那句「写个 hello world 函数」，是怎么从一句话变成一次精准文件修改的？背后是一套叫「代理循环」的机制，搞懂它，你才算真会用 Claude Code，而不只是会敲命令。</p><blockquote><p>留个问题：你刚让它写 <code>test.py</code> 时，它是<strong>先看了目录里有什么文件、还是直接动手写的</strong>？这个差别，正是下一篇的切入点。</p></blockquote><hr><p>装好只是拿到了工具，会用它的「思路」才是真本事——下一篇见。</p>',148)])])}const u=a(n,[["render",o]]);export{g as __pageData,u as default};
